#!/usr/bin/env python3
"""
Dependency Management Script for Python Projects
===============================================

This script provides tools for managing Python dependency lock files
to ensure consistent versions across development and production environments.

Usage:
    python dependency_manager.py generate
    python dependency_manager.py update
    python dependency_manager.py verify
"""

import os
import sys
import subprocess
import hashlib
import json
from pathlib import Path
from typing import List, Dict, Optional

class DependencyManager:
    def __init__(self, project_root: str = "."):
        self.project_root = Path(project_root)
        self.requirements_file = self.project_root / "requirements.txt"
        self.poetry_lock_file = self.project_root / "poetry.lock"
        self.requirements_hash_file = self.project_root / "requirements.hash"
        
    def generate_requirements_txt(self) -> bool:
        """Generate requirements.txt with hashes using pip-compile"""
        try:
            subprocess.run([
                "pip-compile", 
                "--generate-hashes", 
                "--output-file", 
                str(self.requirements_file),
                "requirements.in"
            ], check=True, capture_output=True)
            print("✅ Generated requirements.txt with hashes")
            return True
        except subprocess.CalledProcessError as e:
            print(f"❌ Failed to generate requirements.txt: {e}")
            return False
    
    def generate_poetry_lock(self) -> bool:
        """Generate poetry.lock file"""
        try:
            subprocess.run(["poetry", "lock", "--no-update"], check=True, capture_output=True)
            print("✅ Generated poetry.lock file")
            return True
        except subprocess.CalledProcessError as e:
            print(f"❌ Failed to generate poetry.lock: {e}")
            return False
    
    def update_dependencies(self) -> bool:
        """Update dependencies in both formats"""
        success = True
        
        # Update requirements.txt
        if self.requirements_file.exists():
            try:
                subprocess.run(["pip-compile", "--upgrade", "--generate-hashes"], check=True, capture_output=True)
                print("✅ Updated requirements.txt")
            except subprocess.CalledProcessError as e:
                print(f"❌ Failed to update requirements.txt: {e}")
                success = False
        
        # Update poetry.lock
        if self.poetry_lock_file.exists():
            try:
                subprocess.run(["poetry", "lock", "--no-update"], check=True, capture_output=True)
                print("✅ Updated poetry.lock")
            except subprocess.CalledProcessError as e:
                print(f"❌ Failed to update poetry.lock: {e}")
                success = False
        
        return success
    
    def verify_dependencies(self) -> bool:
        """Verify that dependencies are consistent"""
        if not self.requirements_file.exists() and not self.poetry_lock_file.exists():
            print("⚠️  No dependency files found")
            return False
        
        if self.requirements_file.exists():
            print("🔍 Verifying requirements.txt...")
            try:
                subprocess.run(["pip-check", str(self.requirements_file)], check=True, capture_output=True)
                print("✅ requirements.txt is valid")
            except subprocess.CalledProcessError as e:
                print(f"❌ requirements.txt verification failed: {e}")
                return False
        
        if self.poetry_lock_file.exists():
            print("🔍 Verifying poetry.lock...")
            try:
                subprocess.run(["poetry", "check"], check=True, capture_output=True)
                print("✅ poetry.lock is valid")
            except subprocess.CalledProcessError as e:
                print(f"❌ poetry.lock verification failed: {e}")
                return False
        
        return True
    
    def get_dependency_hashes(self) -> Dict[str, str]:
        """Extract hashes from requirements.txt"""
        hashes = {}
        if not self.requirements_file.exists():
            return hashes
        
        try:
            with open(self.requirements_file, 'r') as f:
                for line in f:
                    if line.startswith('-h ') or line.startswith('--hash'):
                        parts = line.strip().split()
                        if len(parts) > 1:
                            hashes[parts[1]] = hashlib.sha256(parts[1].encode()).hexdigest()
        except Exception as e:
            print(f"Error reading requirements.txt: {e}")
        
        return hashes
    
    def create_requirements_in(self) -> bool:
        """Create requirements.in file with minimal dependencies"""
        requirements_in = self.project_root / "requirements.in"
        if requirements_in.exists():
            print("⚠️  requirements.in already exists")
            return True
        
        try:
            with open(requirements_in, 'w') as f:
                f.write("# Base dependencies\n")
                f.write("django>=4.0,<5.0\n")
                f.write("requests>=2.25.0\n")
                f.write("psycopg2-binary>=2.9.0\n")
            print("✅ Created requirements.in")
            return True
        except Exception as e:
            print(f"❌ Failed to create requirements.in: {e}")
            return False

def main():
    manager = DependencyManager()
    
    if len(sys.argv) < 2:
        print("Usage: python dependency_manager.py [generate|update|verify]")
        sys.exit(1)
    
    command = sys.argv[1]
    
    if command == "generate":
        success = manager.create_requirements_in()
        if success:
            manager.generate_requirements_txt()
            manager.generate_poetry_lock()
        print("✅ Dependency generation complete")
    
    elif command == "update":
        manager.update_dependencies()
        print("✅ Dependency update complete")
    
    elif command == "verify":
        manager.verify_dependencies()
        print("✅ Dependency verification complete")
    
    else:
        print("Unknown command. Use: generate, update, or verify")
        sys.exit(1)

if __name__ == "__main__":
    main()